class Ledger:
    def __init__(self, limits=None):
        self.limits = dict(limits) if limits else {}
        self.balances = {}

    def debit(self, agent_id, amount):
        current = self.balances.get(agent_id, 0.0)
        limit = self.limits.get(agent_id)
        if limit is not None and current + amount > limit:
            return False
        self.balances[agent_id] = current + amount
        return True

    def balance(self, agent_id):
        return self.balances.get(agent_id, 0.0)

