files.budget_config.py:
def load_config(raw):
    """Load a per-agent budget threshold config from a raw dict.

    Validates that all values are non-negative numbers (int/float, not bool)
    and returns a normalized dict of floats.
    """
    if not isinstance(raw, dict):
        raise ValueError("config must be a dict")
    cfg = {}
    for agent, value in raw.items():
        if isinstance(value, bool) or not isinstance(value, (int, float)):
            raise ValueError(f"budget for {agent!r} must be numeric")
        if value < 0:
            raise ValueError(f"budget for {agent!r} must be non-negative")
        cfg[agent] = float(value)
    return cfg


def is_over_budget(cfg, agent, spent):
    """Return True if spent exceeds the configured budget for agent.

    Unknown agents (not in cfg) are never considered over budget.
    """
    if agent not in cfg:
        return False
    return spent > cfg[agent]

